    // PATCH /api/admin/users/:id/plan — quickly upgrade/downgrade a user's plan (admin only)
    app.patch("/api/admin/users/:id/plan", auth_1.isAuthenticated, isAdmin, async (req, res) => {
        try {
            const adminId = req.user?.claims?.sub;
            const { id: userId } = req.params;
            const { plan } = req.body;
            // 2026-06: previously only allowed 'free' | 'pro' which meant admins
            // could not manually grant trial / monthly / yearly / pro_referral tiers
            // via the admin UI — they had to use the upgrade endpoint instead. Now
            // accepts every real plan ID.
            const VALID_ADMIN_PLANS = ["free", "trial", "basic", "monthly", "yearly", "pro", "pro_referral"];
            if (!plan || !VALID_ADMIN_PLANS.includes(plan)) {
                return res.status(400).json({
                    message: `plan must be one of: ${VALID_ADMIN_PLANS.join(", ")}`,
                });
            }
            if (plan === "free") {
                // Downgrade: deactivate all subscriptions AND reset plan column
                await db_1.db.update(schema_1.userSubscriptions).set({ status: "expired", updatedAt: new Date() }).where((0, drizzle_orm_1.eq)(schema_1.userSubscriptions.userId, userId));
                await db_1.db.update(auth_3.users).set({ plan: "free", updatedAt: new Date() }).where((0, drizzle_orm_1.eq)(auth_3.users.id, userId));
                console.info(`[Admin] Manual plan downgrade: userId=${userId} plan=free by=${adminId}`);
                return res.json({ success: true, plan: "free" });
            }
            // Upgrade: create subscription record and sync plan column
            const transactionCode = `ADMIN-MANUAL-${Date.now()}`;
            const dbPlan = await storage_1.storage.getPlanById(plan);
            const payment = await storage_1.storage.createPayment({
                userId,
                amount: dbPlan?.price ?? 0,
                baseAmount: dbPlan?.price ?? 0, // no discount on admin panel upgrade
                discountType: null,
                currency: "KES",
                method: "mpesa",
                status: "success",
                serviceId: `plan_${plan}`,
                transactionRef: transactionCode,
                metadata: JSON.stringify({ adminGranted: true, grantedBy: adminId, note: "Manual upgrade via admin panel" }),
            });
            const expiresAt = (0, plans_1.planExpiry)(plan);
            await storage_1.storage.activateUserPlan(userId, plan, payment.id, expiresAt);
            console.info(`[Admin] Manual plan upgrade: userId=${userId} plan=${plan} by=${adminId}`);
            res.json({ success: true, plan });
        }
        catch (error) {
            console.error("Error upgrading user plan:", error);
            res.status(500).json({ message: "Failed to upgrade plan", error: error.message });
        }
    });
