    app.get("/api/agencies/rating-eligibility", auth_1.isAuthenticated, async (req, res) => {
        try {
            const userId = req.user?.claims?.sub;
            if (!userId)
                return res.status(401).json({ eligible: false, reason: "Not logged in" });
            const [userRow] = await db_1.db
                .select({ createdAt: auth_3.users.createdAt })
                .from(auth_3.users)
                .where((0, drizzle_orm_1.eq)(auth_3.users.id, userId))
                .limit(1);
            if (!userRow?.createdAt)
                return res.json({ eligible: false, daysOld: 0, reason: "Account not found" });
            const daysOld = Math.floor((Date.now() - new Date(userRow.createdAt).getTime()) / (1000 * 60 * 60 * 24));
            const eligible = daysOld >= 7;
            res.json({ eligible, daysOld, reason: eligible ? null : `Account must be at least 7 days old (yours is ${daysOld} day${daysOld === 1 ? "" : "s"} old)` });
        }
        catch (err) {
            console.error("[RatingEligibility]", err);
            res.status(500).json({ eligible: false, reason: "Server error" });
        }
    });
