    // Public endpoint for user agent portal license check
    app.get("/api/license-check", auth_1.isAuthenticated, async (req, res) => {
        try {
            const agencies = await storage_1.storage.getNeaAgencies();
            const now = new Date();
            const result = agencies.map((agency) => {
                const expiryDate = new Date(agency.expiryDate);
                const diffMs = expiryDate.getTime() - now.getTime();
                const daysRemaining = Math.ceil(diffMs / (1000 * 60 * 60 * 24));
                let status;
                if (daysRemaining < 0)
                    status = "expired";
                else if (daysRemaining <= 30)
                    status = "expiring_soon";
                else if (daysRemaining <= 60)
                    status = "expiring_60";
                else
                    status = "valid";
                const needsRenewal = daysRemaining <= 60;
                return {
                    id: agency.id,
                    agencyName: agency.agencyName,
                    licenseNumber: agency.licenseNumber,
                    issuingAuthority: "National Employment Authority (NEA)",
                    expiryDate: agency.expiryDate,
                    daysRemaining,
                    status,
                    needsRenewal,
                };
            });
            res.json(result);
        }
        catch (error) {
            console.error("Error fetching license check:", error);
            res.status(500).json({ message: "Failed to fetch license data" });
        }
    });
