    app.get("/api/map/agencies", async (req, res) => {
        try {
            const { country, status, minScore, maxScore, industry, search } = req.query;
            const allAgencies = await storage_1.storage.getNeaAgencies(search);
            const results = [];
            for (const agency of allAgencies) {
                if (!agency.latitude || !agency.longitude)
                    continue;
                const isBlacklisted = await storage_1.storage.isEntityBlacklisted(agency.id);
                if (isBlacklisted)
                    continue;
                const score = await storage_1.storage.getAgencyScore(agency.id);
                const now = new Date();
                const expiryDate = agency.expiryDate ? new Date(agency.expiryDate) : null;
                const daysUntilExpiry = expiryDate ? Math.ceil((expiryDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)) : null;
                let licenseStatus = "valid";
                if (agency.statusOverride === "suspended")
                    licenseStatus = "suspended";
                else if (expiryDate && expiryDate < now)
                    licenseStatus = "expired";
                else if (daysUntilExpiry !== null && daysUntilExpiry <= 30)
                    licenseStatus = "expiring_soon";
                if (country && agency.country && agency.country.toLowerCase() !== country.toLowerCase())
                    continue;
                if (status && licenseStatus !== status)
                    continue;
                if (industry && agency.serviceType && !agency.serviceType.toLowerCase().includes(industry.toLowerCase()))
                    continue;
                if (minScore && score && score.overallScore < parseInt(minScore))
                    continue;
                if (maxScore && score && score.overallScore > parseInt(maxScore))
                    continue;
                let markerColor = "gray";
                if (licenseStatus === "valid" && score && score.overallScore >= 60)
                    markerColor = "green";
                else if (licenseStatus === "expiring_soon" || (score && score.overallScore >= 40 && score.overallScore < 60))
                    markerColor = "yellow";
                else if (licenseStatus === "expired" || licenseStatus === "suspended")
                    markerColor = "red";
                results.push({
                    id: agency.id,
                    agencyName: agency.agencyName,
                    licenseNumber: agency.licenseNumber,
                    latitude: parseFloat(agency.latitude),
                    longitude: parseFloat(agency.longitude),
                    country: agency.country || "Kenya",
                    city: agency.city || "Unknown",
                    serviceType: agency.serviceType,
                    licenseStatus,
                    expiryDate: agency.expiryDate,
                    markerColor,
                    legitimacyScore: score ? { overallScore: score.overallScore, tier: score.tier } : null,
                });
            }
            res.json(results);
        }
        catch (error) {
            console.error("Map agencies error:", error);
            res.status(500).json({ message: "Failed to fetch map data" });
        }
    });
